example.code:
#[cfg(test)]
mod tests {
    use super::*;
    use mockall::predicate::*;
    use assert_matches::assert_matches;

    fn create_test_user() -> User {
        User { id: 1, email: "test@example.com".into(), ..Default::default() }
    }

    #[tokio::test(flavor = "multi_thread", worker_threads = 2)]
    async fn test_get_by_id_returns_user() {
        let mut mock_db = MockDatabase::new();
        mock_db.expect_fetch_user_by_id()
            .with(eq(1))
            .times(1)
            .returning(|_| Ok(Some(create_test_user())));

        let service = UserService::new(Arc::new(mock_db));
        let result = service.get_by_id(1).await;

        assert!(result.is_ok());
        assert_eq!(result.unwrap().email, "test@example.com");
    }

    #[tokio::test]
    async fn test_get_by_id_not_found() {
        let mut mock_db = MockDatabase::new();
        mock_db.expect_fetch_user_by_id()
            .returning(|_| Ok(None));

        let service = UserService::new(Arc::new(mock_db));
        let result = service.get_by_id(999).await;

        assert_matches!(result, Err(AppError::NotFound(_)));
    }
}
